import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../../api/api";

const T = {
  accent:"#14B8A6", accent2:"#0F766E", text:"#1E293B", muted:"#64748B",
  border:"#E2E8F0", card:"#FFFFFF", pageBg:"#F1F5F9",
  success:"#10B981", warn:"#F59E0B", danger:"#EF4444", indigo:"#6366F1", blue:"#3B82F6",
};
const fonts = `https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Plus+Jakarta+Sans:wght@500;600;700&display=swap`;

const Icon = ({ d, size=18, color=T.accent, stroke=1.8 }) => (
  <svg width={size} height={size} fill="none" viewBox="0 0 24 24"
    stroke={color} strokeWidth={stroke} strokeLinecap="round" strokeLinejoin="round">
    <path d={d}/>
  </svg>
);

const StatCard = ({ label, value, color, icon }) => (
  <div style={{ background:T.card, borderRadius:14, padding:"22px 20px", border:`1px solid ${T.border}`,
    boxShadow:"0 1px 3px rgba(0,0,0,0.05)", flex:1, position:"relative", overflow:"hidden", minWidth:160 }}>
    <div style={{ position:"absolute", top:-16, right:-16, width:64, height:64,
      borderRadius:"50%", background:color+"18" }}/>
    <div style={{ width:36, height:36, borderRadius:9, background:color+"1C",
      display:"flex", alignItems:"center", justifyContent:"center", marginBottom:12 }}>
      <Icon d={icon} color={color} size={17}/>
    </div>
    <div style={{ fontSize:28, fontWeight:700, color:T.text, lineHeight:1,
      fontFamily:"'Plus Jakarta Sans',sans-serif" }}>{value}</div>
    <div style={{ fontSize:12, color:T.muted, marginTop:5, fontWeight:500,
      fontFamily:"'Inter',sans-serif" }}>{label}</div>
  </div>
);

const AdminDashboard = () => {
  const navigate = useNavigate();
  const [stats, setStats]     = useState({ clients:0, freelancers:0, projects:0, proposals:0 });
  const [projects, setProjects] = useState([]);
  const [loading, setLoading]   = useState(true);

  useEffect(() => {
    (async () => {
      try {
        const [users, projs, props] = await Promise.all([
          API.get("/users"),
          API.get("/projects"),
          API.get("/proposals/my").catch(() => ({ data:[] })),
        ]);
        const u = users.data || [];
        const p = projs.data || [];
        setStats({
          clients:     u.filter(x => x.role==="client").length,
          freelancers: u.filter(x => x.role==="freelancer").length,
          projects:    p.length,
          proposals:   props.data?.length || 0,
        });
        setProjects(p.slice(0,5));
      } catch {}
      setLoading(false);
    })();
  }, []);

  const fmt = d => d ? new Date(d).toLocaleDateString("en-IN",{day:"2-digit",month:"short",year:"numeric"}) : "—";

  return (
    <div style={{ minHeight:"100vh", background:T.pageBg, fontFamily:"'Inter',sans-serif" }}>
      <link href={fonts} rel="stylesheet"/>
      <div style={{ maxWidth:1100, margin:"0 auto", padding:"32px 28px" }}>

        {/* Header */}
        <div style={{ marginBottom:28 }}>
          <p style={{ fontSize:11, color:T.muted, letterSpacing:1.8, textTransform:"uppercase",
            fontWeight:600, marginBottom:5 }}>Overview</p>
          <h1 style={{ fontSize:24, fontFamily:"'Plus Jakarta Sans',sans-serif", fontWeight:700,
            color:T.text, margin:0, letterSpacing:-0.3 }}>Admin Dashboard</h1>
          <p style={{ color:T.muted, fontSize:13, marginTop:4 }}>Platform statistics and recent activity</p>
        </div>

        {/* Stats */}
        <div style={{ display:"flex", gap:14, marginBottom:28, flexWrap:"wrap" }}>
          <StatCard label="Total Clients"     value={stats.clients}     color={T.blue}    icon="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0z"/>
          <StatCard label="Total Freelancers" value={stats.freelancers} color={T.accent}  icon="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/>
          <StatCard label="Total Projects"    value={stats.projects}    color={T.indigo}  icon="M3 7v10a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-6l-2-2H5a2 2 0 00-2 2z"/>
          <StatCard label="Total Proposals"   value={stats.proposals}   color={T.warn}    icon="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/>
        </div>

        {/* Projects Table */}
        <div style={{ background:T.card, borderRadius:16, border:`1px solid ${T.border}`,
          boxShadow:"0 1px 3px rgba(0,0,0,0.05)", overflow:"hidden" }}>

          <div style={{ padding:"18px 24px", borderBottom:`1px solid ${T.border}`,
            display:"flex", justifyContent:"space-between", alignItems:"center" }}>
            <div style={{ display:"flex", alignItems:"center", gap:10 }}>
              <div style={{ width:32, height:32, borderRadius:8, background:`${T.accent}1A`,
                display:"flex", alignItems:"center", justifyContent:"center" }}>
                <Icon d="M3 7v10a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-6l-2-2H5a2 2 0 00-2 2z" size={15} color={T.accent}/>
              </div>
              <h2 style={{ margin:0, fontSize:14, fontWeight:600, color:T.text,
                fontFamily:"'Plus Jakarta Sans',sans-serif" }}>Project Details</h2>
            </div>
            <button onClick={() => navigate("/admin/projects")} style={{
              fontSize:12, color:T.accent, background:"none", border:"none",
              cursor:"pointer", fontWeight:600, fontFamily:"'Inter',sans-serif",
              display:"flex", alignItems:"center", gap:4 }}>
              View All
              <Icon d="M9 5l7 7-7 7" color={T.accent} size={12} stroke={2.5}/>
            </button>
          </div>

          {/* Table */}
          <div style={{ overflowX:"auto" }}>
            <table style={{ width:"100%", borderCollapse:"collapse" }}>
              <thead>
                <tr style={{ background:"#F8FAFC" }}>
                  {["Title","Status","Budget","Client","Proposals"].map(h => (
                    <th key={h} style={{ padding:"11px 20px", textAlign:"left", fontSize:11,
                      fontWeight:600, color:T.muted, textTransform:"uppercase", letterSpacing:.8,
                      borderBottom:`1px solid ${T.border}`, fontFamily:"'Inter',sans-serif" }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {loading ? (
                  <tr><td colSpan={5} style={{ padding:40, textAlign:"center", color:T.muted }}>Loading...</td></tr>
                ) : projects.length === 0 ? (
                  <tr><td colSpan={5} style={{ padding:40, textAlign:"center", color:T.muted }}>No projects yet</td></tr>
                ) : projects.map((p, i) => (
                  <tr key={p.id} style={{ borderBottom: i<projects.length-1 ? `1px solid ${T.border}` : "none",
                    transition:"background .15s" }}
                    onMouseEnter={e=>e.currentTarget.style.background="#F8FAFC"}
                    onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                    <td style={{ padding:"14px 20px" }}>
                      <span style={{ fontSize:13, fontWeight:600, color:T.text }}>{p.title}</span>
                    </td>
                    <td style={{ padding:"14px 20px" }}>
                      <span style={{ padding:"3px 10px", borderRadius:20, fontSize:10, fontWeight:600,
                        background: p.status==="open" ? "#D1FAE5":"#FEE2E2",
                        color: p.status==="open" ? T.success:T.danger }}>
                        {(p.status||"open").charAt(0).toUpperCase()+(p.status||"open").slice(1)}
                      </span>
                    </td>
                    <td style={{ padding:"14px 20px", fontSize:13, color:T.text, fontWeight:500 }}>
                      ₹{Number(p.budget).toLocaleString()}
                    </td>
                    <td style={{ padding:"14px 20px", fontSize:13, color:T.muted }}>{p.client_name||"—"}</td>
                    <td style={{ padding:"14px 20px", fontSize:13, color:T.muted }}>{p.proposal_count||0}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* PDF Buttons */}
          <div style={{ padding:"16px 20px", borderTop:`1px solid ${T.border}`,
            display:"flex", gap:10, flexWrap:"wrap" }}>
            <button style={{ display:"flex", alignItems:"center", gap:7, padding:"9px 18px", borderRadius:9,
              background:`linear-gradient(135deg,${T.accent},${T.accent2})`, color:"#fff",
              border:"none", fontSize:12, fontWeight:600, cursor:"pointer",
              fontFamily:"'Inter',sans-serif", boxShadow:`0 3px 10px ${T.accent}30` }}>
              <Icon d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" color="#fff" size={14}/>
              Generate Full PDF Report
            </button>
            <button style={{ display:"flex", alignItems:"center", gap:7, padding:"9px 18px", borderRadius:9,
              background:`${T.accent}12`, color:T.accent, border:`1px solid ${T.accent}25`,
              fontSize:12, fontWeight:600, cursor:"pointer", fontFamily:"'Inter',sans-serif" }}>
              <Icon d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" color={T.accent} size={14}/>
              Generate Today's Login Report
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};
export default AdminDashboard;
